from itertools import permutations, islice


def solution():
    # Use islice to iterate directly to the 1,000,000th permutation
    # without storing all of them in memory.
    digits = "0123456789"
    # 1,000,000th permutation is at index 999,999
    target = islice(permutations(digits), 999999, 1000000)
    return "".join(next(target))


if __name__ == "__main__":
    print(solution())
